 'use client';
import React, { useEffect, useRef, useState } from "react";
import { motion, useInView } from "framer-motion";
import { ClipboardCheck, LineChart, BookOpen, ArrowRight } from "lucide-react";

const steps = [
  {
    icon: ClipboardCheck,
    title: "Tell us your basics",
    desc: "Income, priorities, and a few details to personalize guidance.",
    color: "var(--color-primary-600)",
  },
  {
    icon: LineChart,
    title: "Get actionable steps",
    desc: "Clear next actions with trade-offs and the why behind each suggestion.",
    color: "var(--color-sage)",
  },
  {
    icon: BookOpen,
    title: "Learn as you go",
    desc: "Short lessons with sources to build durable financial literacy.",
    color: "var(--color-accent-600)",
  },
];

function StepCard({ idx, icon: Icon, title, desc, color, delay }: { idx: number; icon: React.ElementType; title: string; desc: string; color: string; delay: number }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const inView = useInView(ref, { once: true, margin: "-20% 0px -20% 0px" });
  const [count, setCount] = useState(0);
  useEffect(() => {
    if (!inView) return;
    let i = 0;
    const target = idx;
    const id = setInterval(() => {
      i += 1;
      if (i > target) {
        clearInterval(id);
      } else {
        setCount(i);
      }
    }, 120);
    return () => clearInterval(id);
  }, [inView, idx]);

  const r = 18;
  const circumference = 2 * Math.PI * r;
  const dashOffset = Math.max(0, circumference * (1 - (inView ? 1 : 0)));

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 24 }}
      animate={inView ? { opacity: 1, y: 0 } : undefined}
      transition={{ duration: 0.6, delay }}
      className="h-full rounded-2xl border bg-white/70 backdrop-blur-sm p-6 shadow-sm relative overflow-hidden group"
    >
      <div className="flex items-center gap-3">
        <div className="relative h-10 w-10">
          <svg className="absolute inset-0" width="40" height="40" viewBox="0 0 40 40">
            <circle cx="20" cy="20" r={r} fill="none" stroke="rgba(0,0,0,0.08)" strokeWidth="3" />
            <motion.circle
              cx="20"
              cy="20"
              r={r}
              fill="none"
              stroke={color}
              strokeWidth="3"
              strokeLinecap="round"
              style={{ strokeDasharray: circumference, strokeDashoffset: dashOffset, transform: "rotate(-90deg)", transformOrigin: "20px 20px" }}
              transition={{ duration: 1.2, ease: "easeInOut", delay }}
            />
          </svg>
          <div className="absolute inset-0 grid place-items-center text-[var(--color-primary-600)] font-semibold text-sm">{count}</div>
        </div>
        <motion.div
          initial={idx === 1 ? { x: -16, opacity: 0 } : idx === 2 ? { scale: 0.85, opacity: 0 } : { rotate: -8, opacity: 0 }}
          animate={inView ? { x: 0, scale: 1, rotate: 0, opacity: 1 } : undefined}
          transition={{ type: "spring", stiffness: 140, damping: 14, delay: delay + 0.1 }}
          className="flex h-12 w-12 items-center justify-center rounded-lg"
          style={{
            background: "radial-gradient(circle at 50% 50%, var(--color-primary-50), transparent 60%)",
            color: "var(--color-primary-600)",
          }}
        >
          <Icon className="h-6 w-6 transition-transform duration-300 group-hover:scale-105 group-hover:-rotate-3" />
        </motion.div>
      </div>
      <h3 className="mt-4 text-lg font-semibold text-gray-900 relative">
        {title}
        <span className="absolute left-0 -bottom-1 h-0.5 w-0 bg-[var(--color-primary-600)] transition-[width] duration-300 ease-in-out group-hover:w-full" />
      </h3>
      <p className="mt-2 text-sm text-gray-700 transition-all duration-300 group-hover:translate-y-[-2px]">{desc}</p>
      <div className="mt-4 flex items-center gap-2 text-[var(--color-sage)] opacity-0 -translate-x-1 transition-all duration-300 group-hover:opacity-100 group-hover:translate-x-0">
        <span className="text-xs">Learn more</span>
        <ArrowRight size={14} />
      </div>
      <motion.div
        initial={{ opacity: 0 }}
        animate={inView ? { opacity: 0.12 } : undefined}
        transition={{ duration: 0.6, delay }}
        className="absolute inset-0 -z-10"
        style={{
          background: `radial-gradient(600px circle at 10% -10%, ${color}22, transparent 60%)`,
        }}
      />
    </motion.div>
  );
}

export default function HowItWorks() {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const containerInView = useInView(containerRef, { once: true, amount: 0.3, margin: "-20% 0px -20% 0px" });

  return (
    <section className="relative snap-start">
      <div className="mx-auto max-w-6xl px-6 py-24 md:py-28">
        <h2 className="text-2xl md:text-3xl font-semibold tracking-tight text-gray-900 mb-8 md:mb-10">How it works</h2>
        <div ref={containerRef} className="relative">
          <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-2">
            <StepCard idx={1} icon={ClipboardCheck} title={steps[0].title} desc={steps[0].desc} color={steps[0].color} delay={0.0} />
            <StepCard idx={2} icon={LineChart} title={steps[1].title} desc={steps[1].desc} color={steps[1].color} delay={0.6} />
          </div>
          <div className="mt-6 grid gap-6 lg:grid-cols-1">
            <StepCard idx={3} icon={BookOpen} title={steps[2].title} desc={steps[2].desc} color={steps[2].color} delay={1.2} />
          </div>

          <div className="pointer-events-none absolute inset-0 -z-10 hidden sm:block">
            <motion.svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
              <defs>
                <linearGradient id="hiwStroke" x1="0" x2="1" y1="0" y2="0">
                  <stop offset="0%" stopColor="var(--color-primary-600)" />
                  <stop offset="50%" stopColor="var(--color-sage)" />
                  <stop offset="100%" stopColor="var(--color-accent-600)" />
                </linearGradient>
              </defs>
              <motion.path
                d="M 25 28 L 75 28"
                initial={{ pathLength: 0 }}
                animate={containerInView ? { pathLength: 1 } : undefined}
                transition={{ duration: 1.0, ease: "easeInOut", delay: 0.4 }}
                stroke="url(#hiwStroke)"
                strokeWidth="0.6"
                strokeLinecap="round"
                fill="none"
              />
              <motion.path
                d="M 50 28 L 50 70"
                initial={{ pathLength: 0 }}
                animate={containerInView ? { pathLength: 1 } : undefined}
                transition={{ duration: 1.0, ease: "easeInOut", delay: 1.0 }}
                stroke="url(#hiwStroke)"
                strokeWidth="0.6"
                strokeLinecap="round"
                fill="none"
              />
            </motion.svg>
          </div>

          <div className="pointer-events-none relative block sm:hidden mt-[-8px] mb-[-8px]">
            <motion.svg width="100%" height="96" viewBox="0 0 100 96" preserveAspectRatio="none">
              <defs>
                <linearGradient id="hiwStrokeMobile" x1="0" x2="0" y1="0" y2="1">
                  <stop offset="0%" stopColor="var(--color-primary-600)" />
                  <stop offset="100%" stopColor="var(--color-accent-600)" />
                </linearGradient>
              </defs>
              <motion.path
                d="M 50 10 L 50 86"
                initial={{ pathLength: 0 }}
                whileInView={{ pathLength: 1 }}
                transition={{ duration: 1.2, ease: "easeInOut" }}
                stroke="url(#hiwStrokeMobile)"
                strokeWidth="1"
                strokeLinecap="round"
                fill="none"
              />
            </motion.svg>
          </div>
        </div>
      </div>
    </section>
  );
}
